-- Migration 005: Create changelog table for update logs
-- Run this in Supabase SQL Editor

CREATE TABLE IF NOT EXISTS changelog (
  id          serial PRIMARY KEY,
  version     text NOT NULL,
  title_en    text NOT NULL,
  title_fr    text NOT NULL,
  body_en     text NOT NULL DEFAULT '',
  body_fr     text NOT NULL DEFAULT '',
  created_at  timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS changelog_version_idx ON changelog (created_at DESC);

-- Seed: 1.86 → 1.49 one row per release; **1.0–1.48** = single aggregate row (same copy for all). Newest first. Re-running may duplicate rows unless you TRUNCATE changelog first.
-- Existing DB missing latest? Run `migrations/insert-changelog-1.86.sql` (or older insert-*.sql) in Supabase SQL Editor (once per version).
;
